# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using System.Threading.Tasks;

public class EventBookingSystemContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    
    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseSqlServer(@"Your_Connection_String");
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int TotalSeats { get; set; }
    public int BookedSeats { get; set; }
}

public class ConcurrentTicketPurchaseService
{
    private readonly EventBookingSystemContext _context;
    
    public ConcurrentTicketPurchaseService(EventBookingSystemContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTickets(int eventId, int quantity)
    {
        var evnt = await _context.Events.SingleOrDefaultAsync(e => e.Id == eventId);
        
        if (evnt is null || evnt.TotalSeats - evnt.BookedSeats < quantity) return false;

        evnt.BookedSeats += quantity;
        
        await _context.SaveChangesAsync();
        
        return true;
    }
}